#pragma once  #include <QObject> #include <QString> #include <QStringList> #include <QDateTime> #include "../market/marketdata.h"  enum class SignalType {     NONE = 0,     BUY = 1,     SELL = 2,     STOP_LOSS = 3,     TAKE_PROFIT = 4 };  enum class StrategyType {     DoubleMA = 0,     ProsperityGrowth = 1 };  struct StrategySignal {     SignalType type;     QString symbol;     double price;     double volume;     QDateTime timestamp;     QString comment; };  struct DoubleMAConfig {     int fastMA = 5;     int slowMA = 20;     int barPeriodMinutes = 5;     double minSpreadPercent = 0.25;     int confirmationBars = 2;     int cooldownBars = 5;     bool requireSlowMAUp = true;     bool blockLateBuy = true;     double minRewardCostMultiple = 2.0; };  struct GrowthBuyConfig {     QStringList enabledTracks;     bool requireMA60Up = true;     bool requireVolumePullback = true;     bool requirePullbackToMA20OrMA60 = true;     bool profitGrowthConfirmed = true;     bool orderLandingConfirmed = true;     bool noPureConceptConfirmed = true;     int pullbackMinDays = 3;     int pullbackMaxDays = 5; };  struct RiskConfig {     double stopLossPercent = 2.0;     double takeProfitPercent = 5.0;     double surgeTakeProfitPercent = 25.0;     bool partialTakeProfitEnabled = true;     bool breakMA60VolumeStopEnabled = true; };  struct PositionConfig {     double lotSize = 0.0;     double maxSingleTrackPercent = 20.0;     int diversifyTrackCount = 3; };  struct StrategyConfig {     StrategyType strategyType = StrategyType::DoubleMA;     QString symbol = QStringLiteral("000001.SH");     DoubleMAConfig doubleMAConfig;     GrowthBuyConfig growthBuyConfig;     RiskConfig riskConfig;     PositionConfig positionConfig; };  struct StrategyParameters {     QString symbol;     int fastMA;     int slowMA;     int barPeriodMinutes = 5;     double stopLossPercent;     double takeProfitPercent;     double lotSize; };  class StrategyBase : public QObject {     Q_OBJECT  signals:     void signalGenerated(const StrategySignal& signal);  public:     explicit StrategyBase(QObject *parent = nullptr);     virtual ~StrategyBase() = default;      virtual void setParameters(const StrategyParameters& params);     virtual void setConfig(const StrategyConfig& config);     const StrategyConfig& config() const { return m_config; }     void syncPositionState(bool hasPosition, double entryPrice);     virtual void processMarketData(const MarketData& data) = 0;     virtual void reset();  protected:     void emitSignal(SignalType type, double price, double volume, const QString& comment = "");  protected:     StrategyConfig m_config;     StrategyParameters m_params;     QString m_symbol;     bool m_hasPosition;     double m_entryPrice;     double m_stopLossPrice;     double m_takeProfitPrice;     QDateTime m_entryTime; };